<?php function snap($seen){$vals=array_keys($seen);sort($vals,SORT_NUMERIC);$parts=[];$open=false;$st=0;$prev=0;foreach($vals as $v){if(!$open){$st=$prev=$v;$open=true;}elseif($v==$prev+1)$prev=$v;else{$parts[]="[$st,$prev]";$st=$prev=$v;}}if($open)$parts[]="[$st,$prev]";return "[".implode(",",$parts)."]";}$d=preg_split('/\s+/',trim(stream_get_contents(STDIN)));if(count($d)&&$d[0]!==""){$idx=0;$t=intval($d[$idx++]);$cases=[];for($tc=0;$tc<$t;$tc++){$ops=intval($d[$idx++]);$seen=[];$snaps=[];for($i=0;$i<$ops;$i++){$op=$d[$idx++];if($op=="A")$seen[intval($d[$idx++])]=true;else$snaps[]=snap($seen);}$cases[]="[".implode(",",$snaps)."]";}echo implode("\n\n",$cases);}
?>
